#include <stdio.h>
#include <stdlib.h>
typedef long long ll;
int cmp(const void *a, const void *b){
    ll x = ((ll*)a)[0] - ((ll*)b)[0];
    return (x>0) - (x<0);
}
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        ll *L = (ll*)malloc(N*sizeof(ll));
        ll *R = (ll*)malloc(N*sizeof(ll));
        for(int i=1;i<=N;i++){
            ll w; scanf("%lld", &w);
            L[i-1] = (ll)i - w;
            R[i-1] = (ll)i - 1;
        }
        // pack intervals into array of pairs for qsort
        ll *arr = (ll*)malloc(2*N*sizeof(ll));
        for(int i=0;i<N;i++){
            arr[2*i] = L[i];
            arr[2*i+1] = R[i];
        }
        // sort by left endpoint using custom comparator on pairs
        qsort(arr, N, 2*sizeof(ll), cmp);
        ll ans = 0;
        ll curL = arr[0], curR = arr[1];
        for(int i=1;i<N;i++){
            ll l = arr[2*i];
            ll r = arr[2*i+1];
            if(l > curR + 1){
                ans += curR - curL + 1;
                curL = l; curR = r;
            }else{
                if(r > curR) curR = r;
            }
        }
        ans += curR - curL + 1;
        printf("%lld\n", ans);
        free(L); free(R); free(arr);
    }
    return 0;
}

