#include <bits/stdc++.h>
using namespace std;
using int64 = long long;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        vector<pair<int64,int64>> segs;
        segs.reserve(N);
        for(int i=1;i<=N;i++){
            int64 w; cin>>w;
            int64 L = (int64)i - w;
            int64 R = (int64)i - 1;
            segs.emplace_back(L,R);
        }
        sort(segs.begin(), segs.end());
        int64 ans = 0;
        int64 curL = segs[0].first, curR = segs[0].second;
        for(size_t i=1;i<segs.size();++i){
            int64 l = segs[i].first, r = segs[i].second;
            if(l > curR + 1){
                ans += curR - curL + 1;
                curL = l; curR = r;
            }else{
                curR = max(curR, r);
            }
        }
        ans += curR - curL + 1;
        cout << ans << '\n';
    }
    return 0;
}

