import java.io.*;
import java.util.*;

public class Main {
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in){ this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException {
            int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false;
            if (c == '-') { neg = true; c = readByte(); }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder sb = new StringBuilder();
        int T = fs.nextInt();
        while (T-- > 0) {
            int N = fs.nextInt();
            long[][] seg = new long[N][2];
            for (int i = 1; i <= N; i++) {
                long w = fs.nextLong();
                long L = i - w;
                long R = i - 1;
                seg[i-1][0] = L;
                seg[i-1][1] = R;
            }
            Arrays.sort(seg, Comparator.comparingLong(a -> a[0]));
            long ans = 0;
            long curL = seg[0][0];
            long curR = seg[0][1];
            for (int i = 1; i < N; i++) {
                long l = seg[i][0];
                long r = seg[i][1];
                if (l > curR + 1) {
                    ans += curR - curL + 1;
                    curL = l; curR = r;
                } else {
                    if (r > curR) curR = r;
                }
            }
            ans += curR - curL + 1;
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

